import numpy as np

def update_edge_distance(edge_distance, local_opt_tours, edge_n_used):
    # Deflation factors to promote new paths
    base_deflation_factor = 0.95

    # Update usage count for edges in the tours
    n = edge_distance.shape[0]
    for tour in local_opt_tours:
        for i in range(len(tour)):
            if i == len(tour) - 1:
                from_node, to_node = tour[i], tour[0]
            else:
                from_node, to_node = tour[i], tour[i+1]
            edge_n_used[from_node, to_node] += 1
            edge_n_used[to_node, from_node] += 1

    # Find the lower usage thresholds to promote less used edges
    lower_usage_threshold = np.percentile(edge_n_used, 30)

    # Update distances based on usage
    updated_edge_distance = np.copy(edge_distance)
    for i in range(n):
        for j in range(n):
            if edge_n_used[i, j] <= lower_usage_threshold:
                updated_edge_distance[i, j] *= base_deflation_factor

    return updated_edge_distance
